           ".cache/pip"
           ".cache/quickshell"
           ".cache/illogical-impulse"
           ".cache/nvidia"
-          ".cache/Jan"
-          ".cache/jan.ai.app"
         ];
         local = [
           ".local/share/npm-global"
           ".local/share/go"
